import React, { useState, useEffect } from 'react';
import { BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { TrendingUp, Users, ThumbsUp, MessageCircle, Eye, Plus, Trash2, RefreshCw, Loader } from 'lucide-react';
import { addChannel, getChannels, refreshChannel, deleteChannel } from './api';

export default function YouTubeAnalyzer() {
  const [channels, setChannels] = useState([]);
  const [channelInput, setChannelInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [selectedChannelId, setSelectedChannelId] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [error, setError] = useState(null);
  const [refreshing, setRefreshing] = useState({});

  useEffect(() => {
    loadChannels();
  }, []);

  const loadChannels = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await getChannels();
      setChannels(data);
    } catch (err) {
      setError('채널 목록을 불러올 수 없습니다: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAddChannel = async () => {
    if (!channelInput.trim()) {
      setError('채널 ID를 입력하세요');
      return;
    }

    try {
      setLoading(true);
      setError(null);
      const newChannel = await addChannel(channelInput.trim());
      setChannels([...channels, newChannel]);
      setChannelInput('');
      setShowAddForm(false);
      setSelectedChannelId(newChannel._id);
    } catch (err) {
      setError('채널 추가 실패: ' + err.response?.data?.error || err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleRefreshChannel = async (channelId) => {
    try {
      setRefreshing({ ...refreshing, [channelId]: true });
      setError(null);
      const result = await refreshChannel(channelId);

      setChannels(channels.map(ch => 
        ch._id === channelId ? result.channel : ch
      ));

      if (result.newVideosDetected > 0) {
        setError(`✓ ${result.newVideosDetected}개의 새 영상이 감지되었습니다`);
      }
    } catch (err) {
      setError('새로고침 실패: ' + err.message);
    } finally {
      setRefreshing({ ...refreshing, [channelId]: false });
    }
  };

  const handleDeleteChannel = async (channelId) => {
    if (!window.confirm('이 채널을 삭제하시겠습니까?')) return;

    try {
      setError(null);
      await deleteChannel(channelId);
      setChannels(channels.filter(ch => ch._id !== channelId));
      if (selectedChannelId === channelId) {
        setSelectedChannelId(null);
      }
    } catch (err) {
      setError('삭제 실패: ' + err.message);
    }
  };

  const calculateEngagement = (videos) => {
    if (!videos || videos.length === 0) return 0;
    const totalEngagement = videos.reduce((sum, video) => {
      const engagement = (video.likes + video.comments) / (video.views || 1);
      return sum + engagement;
    }, 0);
    return ((totalEngagement / videos.length) * 100).toFixed(2);
  };

  const predictPPLRevenue = (videos, productPrice = 50000) => {
    if (!videos || videos.length === 0) {
      return { avgViews: 0, engagement: 0, predictedSales: 0, riskLevel: '평가 불가' };
    }

    const engagement = parseFloat(calculateEngagement(videos)) / 100;
    const avgViews = videos.reduce((sum, v) => sum + (v.views || 0), 0) / videos.length;

    const conversionRate = 0.03;
    const predictedSales = avgViews * engagement * conversionRate * productPrice;

    return {
      avgViews: Math.round(avgViews),
      engagement: engagement.toFixed(4),
      predictedSales: Math.round(predictedSales),
      riskLevel: engagement > 0.05 ? '낮음' : engagement > 0.02 ? '중간' : '높음'
    };
  };

  const prepareChartData = (videos) => {
    if (!videos || videos.length === 0) return [];
    return videos
      .sort((a, b) => new Date(a.uploadDate) - new Date(b.uploadDate))
      .slice(-10)
      .map(v => ({
        name: v.title.substring(0, 15) + '...',
        views: v.views,
        likes: v.likes,
        comments: v.comments,
        engagement: ((v.likes + v.comments) / (v.views || 1) * 100).toFixed(2)
      }));
  };

  const selectedChannel = channels.find(ch => ch._id === selectedChannelId);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900">
      <div className="bg-black bg-opacity-50 border-b border-slate-700 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-6 py-6">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-3xl font-bold text-white">📊 YouTube PPL 분석기</h1>
              <p className="text-slate-400 mt-1">
                {channels.length > 0 
                  ? `${channels.length}개 채널 분석 중` 
                  : '유튜버 채널 성과 분석 및 PPL 성공률 예측'}
              </p>
            </div>
            <button
              onClick={() => setShowAddForm(true)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg flex items-center gap-2 transition"
              disabled={loading}
            >
              <Plus size={20} /> 채널 추가
            </button>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-8">
        {error && (
          <div className={`mb-6 p-4 rounded-lg ${
            error.includes('✓') ? 'bg-green-900 text-green-200 border border-green-700' 
            : 'bg-red-900 text-red-200 border border-red-700'
          }`}>
            {error}
            <button 
              onClick={() => setError(null)}
              className="float-right text-lg"
            >
              ✕
            </button>
          </div>
        )}

        {showAddForm && (
          <div className="bg-slate-800 border border-slate-700 rounded-lg p-6 mb-8">
            <h2 className="text-xl font-bold text-white mb-4">유튜브 채널 추가</h2>
            <div className="flex gap-4">
              <input
                type="text"
                placeholder="예: @MrBeast"
                value={channelInput}
                onChange={(e) => setChannelInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleAddChannel()}
                className="flex-1 bg-slate-700 border border-slate-600 rounded px-4 py-3 text-white placeholder-slate-400 focus:outline-none focus:border-blue-500"
                disabled={loading}
              />
              <button
                onClick={handleAddChannel}
                disabled={loading}
                className="bg-blue-600 hover:bg-blue-700 disabled:bg-slate-600 text-white px-6 py-3 rounded transition flex items-center gap-2"
              >
                {loading ? <Loader size={16} className="animate-spin" /> : <Plus size={16} />}
                {loading ? '추가중...' : '추가'}
              </button>
              <button
                onClick={() => setShowAddForm(false)}
                className="bg-slate-700 hover:bg-slate-600 text-white px-6 py-3 rounded transition"
                disabled={loading}
              >
                닫기
              </button>
            </div>
          </div>
        )}

        {loading && channels.length === 0 ? (
          <div className="bg-slate-800 border border-slate-700 rounded-lg p-12 text-center">
            <Loader size={48} className="mx-auto text-slate-500 mb-4 animate-spin" />
            <p className="text-slate-400">채널 목록을 불러오는 중...</p>
          </div>
        ) : channels.length === 0 ? (
          <div className="bg-slate-800 border border-slate-700 rounded-lg p-12 text-center">
            <Eye size={48} className="mx-auto text-slate-500 mb-4" />
            <h3 className="text-xl font-semibold text-white mb-2">분석할 채널을 추가하세요</h3>
            <p className="text-slate-400 mb-6">유튜브 채널을 추가하면 실시간 통계와 PPL 성공률을 분석할 수 있습니다</p>
            <button
              onClick={() => setShowAddForm(true)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg inline-flex items-center gap-2"
            >
              <Plus size={20} /> 첫 채널 추가하기
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
            <div className="lg:col-span-1">
              <div className="space-y-3 max-h-96 overflow-y-auto">
                {channels.map(channel => (
                  <div
                    key={channel._id}
                    onClick={() => setSelectedChannelId(channel._id)}
                    className={`p-4 rounded-lg border cursor-pointer transition ${
                      selectedChannelId === channel._id
                        ? 'bg-blue-900 border-blue-500'
                        : 'bg-slate-800 border-slate-700 hover:border-slate-600'
                    }`}
                  >
                    <h3 className="font-semibold text-white truncate">{channel.channelName}</h3>
                    <p className="text-sm text-slate-400 mt-1">
                      구독자: {(channel.subscribers/1000).toFixed(0)}K
                    </p>
                    <p className="text-xs text-slate-500 mt-1">
                      영상: {channel.videos?.length || 0}개
                    </p>
                    <div className="flex gap-2 mt-2">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleRefreshChannel(channel._id);
                        }}
                        disabled={refreshing[channel._id]}
                        className="flex-1 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-600 text-white text-xs py-1 rounded transition flex items-center justify-center gap-1"
                      >
                        {refreshing[channel._id] ? (
                          <Loader size={12} className="animate-spin" />
                        ) : (
                          <RefreshCw size={12} />
                        )}
                        {refreshing[channel._id] ? '중...' : '갱신'}
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeleteChannel(channel._id);
                        }}
                        className="bg-red-600 hover:bg-red-700 text-white p-1 rounded transition"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {selectedChannel && (
              <div className="lg:col-span-2 space-y-6">
                <div className="bg-slate-800 border border-slate-700 rounded-lg p-6">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h2 className="text-2xl font-bold text-white">{selectedChannel.channelName}</h2>
                      <p className="text-slate-400 text-sm mt-1">
                        총 {selectedChannel.videos?.length || 0}개 영상 분석
                      </p>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-700 rounded p-4">
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-slate-400 text-sm">총 조회수</p>
                          <p className="text-2xl font-bold text-white mt-1">
                            {(selectedChannel.totalViews / 1000000).toFixed(1)}M
                          </p>
                        </div>
                        <Eye className="text-blue-400" size={32} />
                      </div>
                    </div>

                    <div className="bg-slate-700 rounded p-4">
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-slate-400 text-sm">구독자</p>
                          <p className="text-2xl font-bold text-white mt-1">
                            {(selectedChannel.subscribers / 1000).toFixed(0)}K
                          </p>
                        </div>
                        <Users className="text-green-400" size={32} />
                      </div>
                    </div>

                    <div className="bg-slate-700 rounded p-4">
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-slate-400 text-sm">인게이지먼트율</p>
                          <p className="text-2xl font-bold text-white mt-1">
                            {calculateEngagement(selectedChannel.videos)}%
                          </p>
                        </div>
                        <TrendingUp className="text-yellow-400" size={32} />
                      </div>
                    </div>

                    <div className="bg-slate-700 rounded p-4">
                      <div className="flex items-center justify-between">
                        <div>
                          <p className="text-slate-400 text-sm">평균 댓글</p>
                          <p className="text-2xl font-bold text-white mt-1">
                            {Math.round(
                              (selectedChannel.videos?.reduce((s, v) => s + (v.comments || 0), 0) || 0) / 
                              (selectedChannel.videos?.length || 1)
                            )}
                          </p>
                        </div>
                        <MessageCircle className="text-purple-400" size={32} />
                      </div>
                    </div>
                  </div>
                </div>

                {(() => {
                  const prediction = predictPPLRevenue(selectedChannel.videos);
                  return (
                    <div className="bg-gradient-to-br from-slate-800 to-slate-750 border border-slate-700 rounded-lg p-6">
                      <h3 className="text-xl font-bold text-white mb-4">🎯 PPL 성공률 예측</h3>
                      <div className="grid grid-cols-3 gap-4 mb-4">
                        <div className="bg-slate-700 rounded p-4">
                          <p className="text-slate-400 text-sm">평균 조회수</p>
                          <p className="text-xl font-bold text-white mt-2">{(prediction.avgViews/1000).toFixed(0)}K</p>
                        </div>
                        <div className="bg-slate-700 rounded p-4">
                          <p className="text-slate-400 text-sm">인게이지먼트</p>
                          <p className="text-xl font-bold text-white mt-2">{(prediction.engagement*100).toFixed(2)}%</p>
                        </div>
                        <div className="bg-slate-700 rounded p-4">
                          <p className="text-slate-400 text-sm">위험도</p>
                          <p className={`text-xl font-bold mt-2 ${
                            prediction.riskLevel === '낮음' ? 'text-green-400' : 
                            prediction.riskLevel === '중간' ? 'text-yellow-400' : 
                            'text-red-400'
                          }`}>{prediction.riskLevel}</p>
                        </div>
                      </div>
                      <div className="bg-blue-900 bg-opacity-30 border border-blue-500 rounded p-4">
                        <p className="text-slate-300 text-sm mb-2">예상 PPL 매출 (상품가 50,000원 기준)</p>
                        <p className="text-3xl font-bold text-blue-400">
                          ₩{prediction.predictedSales.toLocaleString()}
                        </p>
                        <p className="text-xs text-slate-400 mt-2">
                          * 예측치는 평균 인게이지먼트율과 3% 전환율 기준입니다
                        </p>
                      </div>
                    </div>
                  );
                })()}
              </div>
            )}
          </div>
        )}

        {selectedChannel && selectedChannel.videos && selectedChannel.videos.length > 0 && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-slate-800 border border-slate-700 rounded-lg p-6">
              <h3 className="text-lg font-bold text-white mb-4">최근 10개 영상 조회수</h3>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={prepareChartData(selectedChannel.videos)}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#475569" />
                  <XAxis dataKey="name" tick={{ fill: '#94a3b8' }} />
                  <YAxis tick={{ fill: '#94a3b8' }} />
                  <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #475569' }} />
                  <Legend />
                  <Bar dataKey="views" fill="#3b82f6" name="조회수" />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="bg-slate-800 border border-slate-700 rounded-lg p-6">
              <h3 className="text-lg font-bold text-white mb-4">좋아요 vs 댓글 분포</h3>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={prepareChartData(selectedChannel.videos)}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#475569" />
                  <XAxis dataKey="name" tick={{ fill: '#94a3b8' }} />
                  <YAxis tick={{ fill: '#94a3b8' }} />
                  <Tooltip contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #475569' }} />
                  <Legend />
                  <Bar dataKey="likes" fill="#ef4444" name="좋아요" />
                  <Bar dataKey="comments" fill="#10b981" name="댓글" />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        <div className="mt-12 text-center text-slate-400 text-sm">
          <p>💡 팁: 정기적으로 데이터를 새로고침하여 최신 통계를 확인하세요</p>
        </div>
      </div>
    </div>
  );
}
